<?php
declare(strict_types=1);
// Grace period and fallback cutoff come from config.php (env-overridable);
// defined() fallbacks keep this file usable standalone in tests.
function tr_default_tz():DateTimeZone{return new DateTimeZone(defined('APP_TZ')?APP_TZ:'Europe/Chisinau');}
function tr_grace_min():int{return defined('MODERATOR_GRACE_MIN')?(int)MODERATOR_GRACE_MIN:20;}
function tr_fallback_cutoff():string{return defined('MODERATOR_FALLBACK_CUTOFF')?(string)MODERATOR_FALLBACK_CUTOFF:'18:00';}
function moderator_cutoff_from_schedule(array $schedule,DateTimeInterface $targetDate,?DateTimeZone $tz=null):?DateTimeImmutable{$tz=$tz?:tr_default_tz();$baseYmd=$targetDate->format('Y-m-d');$maxEndTs=null;foreach($schedule as $row){if(!empty($row['end_time'])&&preg_match('/^(\d{1,2}):(\d{2})$/',(string)$row['end_time'],$m)){$dt=DateTimeImmutable::createFromFormat('Y-m-d H:i',$baseYmd.' '.$m[1].':'.$m[2],$tz);if($dt&&(!$maxEndTs||$dt>$maxEndTs))$maxEndTs=$dt;continue;}$slot=(string)($row['time_slot']??'');if($slot!==''){$slot=str_replace(['–','—','—'],'-',$slot);if(preg_match('/(\d{1,2}):(\d{2})\s*-\s*(\d{1,2}):(\d{2})/',$slot,$m)){$dt=DateTimeImmutable::createFromFormat('Y-m-d H:i',$baseYmd.' '.$m[3].':'.$m[4],$tz);if($dt&&(!$maxEndTs||$dt>$maxEndTs))$maxEndTs=$dt;}}}if(!$maxEndTs)return null;return $maxEndTs->modify('+'.tr_grace_min().' minutes');}
function can_user_edit_for_date(string $role,DateTimeInterface $targetDate,?DateTimeZone $tz=null,array $schedule=[]):array{$tz=$tz?:tr_default_tz();$now=new DateTimeImmutable('now',$tz);$role=strtolower(trim($role??''));if($role==='admin')return[true,''];if($role==='moderator'){$sameDay=$targetDate->format('Y-m-d')===$now->format('Y-m-d');if(!$sameDay)return[false,'Moderators can log/edit only for today.'];$cutoff=moderator_cutoff_from_schedule($schedule,$targetDate,$tz);if(!$cutoff){$cutoff=DateTimeImmutable::createFromFormat('Y-m-d H:i',$now->format('Y-m-d').' '.tr_fallback_cutoff(),$tz);} $ok=$now<=$cutoff;return[$ok,$ok?'':'The moderator window is closed (after last lesson + '.tr_grace_min().' min).'];}if($role==='monitor'){$today=new DateTimeImmutable($now->format('Y-m-d'),$tz);$minDate=$today->modify('-2 days');$ok=($targetDate>=$minDate)&&($targetDate<=$today);return[$ok,$ok?'':'Monitors can edit only today and the previous 2 days.'];}return[false,'Editing not permitted for your role.'];}